// Run Once for All Item
const item = $input.item;
if (!item || !item.json || typeof item.json !== 'object') {
  console.log('[Ashby Parse] empty/invalid input â€” likely fetch error');
  return { json: { jobs: [], company: $('Set Inputs').item.json.company_name || '', error: 'no_response' } };
}
const response = item.json;
const company = $('Set Inputs').item.json;

const jobs = Array.isArray(response.jobs) ? response.jobs : [];

const decodeEntities = (s) => String(s || '')
  .replace(/&amp;/g, '&')
  .replace(/&nbsp;/g, ' ')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  .replace(/&#x27;/g, "'");

const stripHtml = (html) => decodeEntities(html)
  .replace(/<[^>]*>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const isRemote = (j) => {
  if (j.isRemote === true) return true;
  const wp = String(j.workplaceType || '').toLowerCase();
  if (wp === 'remote') return true;
  const loc = String(j.location || '').toLowerCase();
  if (loc.includes('remote')) return true;
  const secondary = Array.isArray(j.secondaryLocations) ? j.secondaryLocations : [];
  return secondary.some(s => String(s?.location || '').toLowerCase().includes('remote'));
};

const normalizeEmploymentType = (t) =>
  String(t || '').toUpperCase().replace(/[-\s]/g, '');

const salaryText = (j) => {
  const comp = j.compensation || {};
  return String(comp.scrapeableCompensationSalarySummary || comp.compensationTierSummary || '').trim();
};

// Exclude unlisted/draft postings (isListed=false). Defaults to including
// when isListed is missing (some payloads omit the field for active jobs).
const listed = jobs.filter(j => j?.isListed !== false);

const normalized = listed.map(job => ({
  company: company.company_name,
  title: String(job.title || '').trim(),
  url: String(job.jobUrl || job.applyUrl || '').trim(),
  description_html: decodeEntities(job.descriptionHtml),
  description: job.descriptionPlain
    ? String(job.descriptionPlain).replace(/\s+/g, ' ').trim()
    : stripHtml(job.descriptionHtml),
  location: String(job.location || '').trim(),
  remote: isRemote(job),
  salary_text: salaryText(job),
  employment_type: normalizeEmploymentType(job.employmentType),
  source: 'ashby',
  posted_at: String(job.publishedAt || '').trim()
}));

console.log(`[Ashby Parse] ${company.company_name} (${company.slug}): ${jobs.length} raw, ${listed.length} listed, ${normalized.length} normalized`);

return normalized.map(j => ({ json: { ...j, _type: 'job' } }));

const config = $('Trigger').first().json.config || {};
const watchlist = $('Trigger').first().json.watchlist || [];

const orderRaw = config.discovery_fetcher_order || '';
const enabledSources = String(orderRaw)
  .split(/[;,]/)
  .map(s => s.trim().toLowerCase())
  .filter(s => s.length > 0);

if (!enabledSources.includes('ashby')) {
  console.log('[Ashby] Disabled via discovery_fetcher_order â€” skipping');
  return [];
}

const thresholdRaw = Number(config.discovery_priority_threshold);
const priorityThreshold = isNaN(thresholdRaw) ? 999 : thresholdRaw;

const companies = watchlist
  .filter(c => {
    if (!c) return false;
    if (String(c.ashby_slug || '').trim().length === 0) return false;
    const p = Number(c.priority);
    const priority = isNaN(p) ? 999 : p;
    return priority <= priorityThreshold;
  })
  .map(c => ({
    company_name: String(c.company_name || '').trim(),
    slug: String(c.ashby_slug || '').trim()
  }));

if (companies.length === 0) {
  console.log(`[Ashby] No companies match priority <= ${priorityThreshold} with ashby_slug â€” skipping`);
  return [];
}

console.log(`[Ashby] Fetching ${companies.length} boards (priority <= ${priorityThreshold})`);
return companies.map(c => ({ json: c }));

const company = $('Set Inputs').item.json;
const runId = $('Trigger').first().json.run_id || '';
const errPayload = $input.first().json || {};
const errObj = errPayload.error || {};

const statusCode = String(
  errObj.httpCode ||
  errObj.status ||
  errObj.cause?.response?.status ||
  ''
);
const message = String(errObj.message || 'Unknown error').substring(0, 500);

console.log(`[Ashby] Fetch failed for ${company.company_name} (${company.slug}): ${statusCode} ${message}`);

return [{
  json: {
    _type: 'failure',
    run_id: runId,
    discovered_at: new Date().toISOString(),
    source: 'ashby',
    company: company.company_name || '',
    slug: company.slug || '',
    status_code: statusCode,
    error_message: message
  }
}];
